 147→function DimensionFields({ part, onUpdate, dispatch, project }) {
 148→  const measurement = Math.round(
 149→    Math.sqrt(
 150→      Math.pow((part.endPoint?.x || 0) - (part.startPoint?.x || 0), 2) +
 151→      Math.pow((part.endPoint?.y || 0) - (part.startPoint?.y || 0), 2) +
 152→      Math.pow((part.endPoint?.z || 0) - (part.startPoint?.z || 0), 2)
 153→    )
 154→  );
 155→
 156→  const handleBoundValueChange = (newVal) => {
 157→    if (!part.boundPartId || !part.boundProperty) return;
 158→    const boundPart = project.parts.find((p) => p.id === part.boundPartId);
 159→    if (!boundPart) return;
 160→    const result = applyDimensionValueToPart(part, newVal, boundPart);
 161→    if (result) {
 162→      dispatch({ type: 'PART_UPDATE', part: { id: result.partId, ...result.changes } });
 163→    }
 164→  };
 165→
 166→  const bindableParts = project.parts.filter((p) => p.type !== 'dimension');
 167→
 168→  const BINDABLE_PROPS = {
 169→    panel: ['width', 'depth', 'thickness'],
 170→    leg: ['width', 'depth', 'height'],
 171→    frame: ['width', 'height', 'length'],
 172→    cutout: ['width', 'height', 'depth'],
 173→    hole: ['diameter', 'depth'],
 174→  };
 175→
 176→  const handleBind = (partId, property) => {
 177→    const target = project.parts.find((p) => p.id === partId);
 178→    if (!target) return;
 179→    const updated = bindDimensionToPart(part, target, property);
 180→    dispatch({ type: 'PART_UPDATE', part: { id: part.id, ...updated } });
 181→  };
 182→
 183→  return (
 184→    <>
 185→      {part.boundPartId ? (
 186→        <NumberInput
 187→          label="Value"
 188→          value={measurement}
 189→          suffix="mm"
 190→          onChange={handleBoundValueChange}
 191→        />
 192→      ) : (
 193→        <NumberInput label="Measured" value={measurement} readOnly suffix="mm" onChange={() => {}} />
 194→      )}
 195→      <NumberInput label="Offset" value={part.offset || 200} onChange={(v) => onUpdate({ offset: v })} />
 196→      <TextInput label="Text Override" value={part.textOverride || ''} onChange={(v) => onUpdate({ textOverride: v || null })} />
 197→      {part.boundPartId && (
 198→        <div className={styles.field}>
 199→          <span className={styles.fieldLabel}>Bound to</span>
 200→          <span className={styles.typeBadge}>{part.boundProperty || 'part'}</span>
 201→        </div>
 202→      )}
 203→      {!part.boundPartId && bindableParts.length > 0 && (
 204→        <BindDimensionUI parts={bindableParts} bindableProps={BINDABLE_PROPS} onBind={handleBind} />
 205→      )}
 206→    </>
 207→  );
