 331→function ConstraintsSection({ part, project, dispatch }) {
 332→  const [showForm, setShowForm] = useState(false);
 333→  const [showSpacingForm, setShowSpacingForm] = useState(false);
 334→  const [cType, setCType] = useState('attach_face');
 335→  const [targetId, setTargetId] = useState('');
 336→  const [srcAnchor, setSrcAnchor] = useState('bottom');
 337→  const [tgtAnchor, setTgtAnchor] = useState('top');
 338→  const [offset, setOffset] = useState(0);
 339→  const [centerAxis, setCenterAxis] = useState('both');
 340→
 341→  const constraints = (project.constraints || []).filter(
 342→    (c) => {
 343→      if (c.type === 'equal_spacing') {
 344→        return (c.partIds || []).includes(part.id) || c.referencePartId === part.id;
 345→      }
 346→      return c.sourcePartId === part.id || c.targetPartId === part.id;
 347→    }
 348→  );
 349→
 350→  const otherParts = project.parts.filter((p) => p.id !== part.id && p.type !== 'dimension');
 351→
 352→  const handleAddConstraint = () => {
 353→    if (!targetId) return;
 354→    const overrides = {
 355→      type: cType,
 356→      sourcePartId: part.id,
 357→      targetPartId: targetId,
 358→      sourceAnchor: srcAnchor,
 359→      targetAnchor: tgtAnchor,
 360→      offset: parseFloat(offset) || 0,
 361→    };
 362→    if (cType === 'center_axis') {
 363→      overrides.axis = centerAxis;
 364→    }
 365→    const constraint = createConstraint(overrides);
 366→    dispatch({ type: 'CONSTRAINT_ADD', constraint });
 367→    setShowForm(false);
 368→    setTargetId('');
 369→  };
 370→
 371→  const formatConstraintLabel = (c) => {
 372→    if (c.type === 'equal_spacing') {
 373→      const names = (c.partIds || []).map((id) => {
 374→        const p = project.parts.find((pp) => pp.id === id);
 375→        return p?.name || '?';
 376→      }).join(', ');
 377→      return `equal_spacing [${c.axis}]: ${names}`;
 378→    }
 379→    const targetPart = project.parts.find((p) => p.id === (c.sourcePartId === part.id ? c.targetPartId : c.sourcePartId));
 380→    const axisLabel = c.type === 'center_axis' && c.axis && c.axis !== 'both' ? ` [${c.axis}]` : '';
 381→    return `${c.type}${axisLabel}: ${c.sourceAnchor} → ${c.targetAnchor} (${targetPart?.name || '?'})`;
 382→  };
 383→
 384→  return (
 385→    <div className={styles.fieldGroup}>
 386→      <span className={styles.groupTitle}>Constraints</span>
 387→      <div className={styles.constraintSection}>
 388→        {constraints.map((c) => (
 389→          <div key={c.id} className={styles.constraintItem}>
 390→            <span>{formatConstraintLabel(c)}</span>
 391→            <button
 392→              className={styles.constraintDelete}
 393→              onClick={() => dispatch({ type: 'CONSTRAINT_DELETE', constraintId: c.id })}
 394→              title="Remove constraint"
 395→            >
 396→              ×
 397→            </button>
 398→          </div>
 399→        ))}
 400→      </div>
 401→
 402→      {showSpacingForm ? (
 403→        <EqualSpacingForm
 404→          part={part}
 405→          project={project}
 406→          dispatch={dispatch}
 407→          onClose={() => setShowSpacingForm(false)}
 408→        />
 409→      ) : !showForm ? (
 410→        <div style={{ display: 'flex', gap: '4px' }}>
 411→          <button className={styles.duplicateBtn} onClick={() => setShowForm(true)}>
 412→            Add Constraint
 413→          </button>
 414→          <button className={styles.duplicateBtn} onClick={() => setShowSpacingForm(true)}>
 415→            Equal Spacing
 416→          </button>
 417→        </div>
 418→      ) : (
 419→        <div className={styles.constraintSection}>
 420→          <SelectInput
 421→            label="Type"
 422→            value={cType}
 423→            options={CONSTRAINT_TYPES.filter((t) => t.value !== 'equal_spacing')}
 424→            onChange={setCType}
 425→          />
 426→          {cType === 'center_axis' && (
