 439→          <SelectInput label="Target Anchor" value={tgtAnchor} options={ANCHOR_OPTIONS} onChange={setTgtAnchor} />
 440→          <NumberInput label="Offset" value={offset} suffix="mm" onChange={setOffset} />
 441→          <div style={{ display: 'flex', gap: '4px' }}>
 442→            <button className={styles.duplicateBtn} onClick={handleAddConstraint}>Create</button>
 443→            <button className={styles.duplicateBtn} onClick={() => setShowForm(false)}>Cancel</button>
