 8→function extractView(sourceView) {
 9→  if (sourceView === 'sketch_object_top' || sourceView === 'sketch_assembly_top') return 'top';
10→  if (sourceView === 'sketch_object_front' || sourceView === 'sketch_assembly_front') return 'front';
11→  if (sourceView === 'sketch_object_side' || sourceView === 'sketch_assembly_side') return 'side';
12→  return 'top';
13→}
