51→export function getSketchViewportSourceLabel(sourceView) {
52→  switch (sourceView) {
53→    case 'sketch_object_top': return 'Object Top';
54→    case 'sketch_object_front': return 'Object Front';
55→    case 'sketch_object_side': return 'Object Side';
56→    case 'sketch_assembly_top': return 'Assembly Top';
57→    case 'sketch_assembly_front': return 'Assembly Front';
58→    case 'sketch_assembly_side': return 'Assembly Side';
59→    case 'sketch_part_detail': return 'Part Detail';
60→    case 'sketch_part_list': return 'Parts List';
61→    default: return 'Unknown';
62→  }
63→}
